import { auth } from '@clerk/nextjs/server';
import { and, eq } from 'drizzle-orm';
import { NextResponse } from 'next/server';

import { db } from '@/libs/DB';
import { logger } from '@/libs/Logger';
import { createWaTemplate, listWaTemplates } from '@/libs/Meta';
import { integrationSchema, waTemplateSchema } from '@/models/Schema';

const getWAIntegration = async (orgId: string) => {
  return db.query.integrationSchema.findFirst({
    where: and(eq(integrationSchema.organizationId, orgId), eq(integrationSchema.type, 'whatsapp')),
  });
};

// GET - list templates from Meta + local DB
export const GET = async (_req: Request) => {
  const { orgId } = await auth();
  if (!orgId) return new NextResponse('Unauthorized', { status: 401 });

  const integration = await getWAIntegration(orgId);
  if (!integration) return NextResponse.json({ error: 'No WhatsApp integration found' }, { status: 404 });

  const config = JSON.parse(integration.config || '{}');
  const wabaId = integration.providerId;

  try {
    const metaTemplates = await listWaTemplates(wabaId || '', integration.accessToken || '');
    return NextResponse.json({ templates: metaTemplates.data || [], wabaId, phoneNumberId: config.phoneNumberId });
  } catch (err: any) {
    logger.error(err, 'Failed to list WA templates');
    return NextResponse.json({ error: err.message }, { status: 500 });
  }
};

// POST - create template on Meta + save locally
export const POST = async (req: Request) => {
  const { orgId } = await auth();
  if (!orgId) return new NextResponse('Unauthorized', { status: 401 });

  const integration = await getWAIntegration(orgId);
  if (!integration) return NextResponse.json({ error: 'No WhatsApp integration found' }, { status: 404 });

  const wabaId = integration.providerId;
  const body = await req.json();
  const { name, language, category, headerText, bodyText, footerText, buttons } = body;

  if (!name || !category || !bodyText) {
    return NextResponse.json({ error: 'name, category, and bodyText are required' }, { status: 400 });
  }

  try {
    const metaResult = await createWaTemplate({
      wabaId: wabaId || '',
      accessToken: integration.accessToken || '',
      name,
      language: language || 'ar',
      category,
      headerText,
      bodyText,
      footerText,
      buttons,
    });

    await db.insert(waTemplateSchema).values({
      organizationId: orgId,
      name,
      language: language || 'ar',
      category,
      headerText,
      bodyText,
      footerText,
      buttons,
      metaStatus: metaResult.status || 'PENDING',
      metaTemplateId: metaResult.id,
    });

    return NextResponse.json({ success: true, id: metaResult.id, status: metaResult.status });
  } catch (err: any) {
    logger.error(err, 'Failed to create WA template');
    return NextResponse.json({ error: err.message }, { status: 500 });
  }
};

'use client';

import {
  AlertCircle,
  CheckCircle2,
  Clock,
  Link as LinkIcon,
  Loader2,
  MessageSquare,
  Phone,
  Plus,
  Trash2,
  XCircle,
} from 'lucide-react';
import React, { useCallback, useEffect, useState } from 'react';

// ШёВӨВҖШёВӨВҖШёВӨВҖ Types ШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖ
type ButtonType = 'URL' | 'PHONE_NUMBER' | 'QUICK_REPLY';
type BtnDraft = { type: ButtonType; text: string; url?: string; phone_number?: string };

type MetaTemplate = {
  id: string;
  name: string;
  status: 'APPROVED' | 'PENDING' | 'REJECTED' | 'PAUSED';
  category: string;
  language: string;
  components: Array<{ type: string; text?: string; format?: string; buttons?: any[] }>;
  rejected_reason?: string;
};

const STATUS_CONFIG: Record<string, { label: string; icon: React.ReactNode; className: string }> = {
  APPROVED: { label: 'в”ҳГ в”ҳГ©в•ӘШ°в”ҳГӘв”ҳВ„', icon: <CheckCircle2 className="size-4" />, className: 'bg-emerald-100 text-emerald-700 border-emerald-200' },
  PENDING: { label: 'в”ҳГ©в”ҳГЁв•ӘВ» в•ӘШҜв”ҳВ„в”ҳГ в•Әв–’в•ӘШҜв•ӘШҙв•Әв•Јв•ӘШұ', icon: <Clock className="size-4" />, className: 'bg-amber-100 text-amber-700 border-amber-200' },
  REJECTED: { label: 'в”ҳГ в•Әв–’в”ҳВҒв”ҳГӘв•Әв•ў', icon: <XCircle className="size-4" />, className: 'bg-red-100 text-red-700 border-red-200' },
  PAUSED: { label: 'в”ҳГ в”ҳГӘв”ҳГ©в”ҳГӘв”ҳВҒ', icon: <AlertCircle className="size-4" />, className: 'bg-slate-100 text-slate-600 border-slate-200' },
};

// ШёВӨВҖШёВӨВҖШёВӨВҖ WhatsApp Phone Preview ШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖ
const WAPreview = ({
  headerText,
  bodyText,
  footerText,
  buttons,
}: {
  headerText?: string;
  bodyText: string;
  footerText?: string;
  buttons: BtnDraft[];
}) => (
  <div className="flex flex-col items-end">
    <div className="w-full max-w-[280px] overflow-hidden rounded-2xl rounded-tr-sm bg-white shadow-lg">
      {headerText && (
        <div className="border-b border-slate-100 bg-slate-50 px-4 py-2.5 text-sm font-semibold text-slate-800">
          {headerText}
        </div>
      )}
      <div className="px-4 py-3">
        <p className="whitespace-pre-wrap text-sm leading-relaxed text-slate-800">
          {bodyText || <span className="italic text-slate-400">в”ҳВҶв•Әв•Ў в•ӘШҜв”ҳВ„в•Әв–’в•Әв”Ӯв•ӘШҜв”ҳВ„в•ӘШұ...</span>}
        </p>
        {footerText && (
          <p className="mt-1.5 text-xs text-slate-400">{footerText}</p>
        )}
        <p className="mt-1.5 text-right text-[10px] text-slate-400">в•ӘШҜв”ҳВ„в•ӘШӘв”ҳВҶ ШёВЈГҙШёВЈГҙ</p>
      </div>
      {buttons.length > 0 && (
        <div className="border-t border-slate-100">
          {buttons.map((btn, i) => (
            <button
              key={i}
              type="button"
              className="flex w-full items-center justify-center gap-1.5 border-b border-slate-100 py-2.5 text-xs font-medium text-sky-600 last:border-b-0 hover:bg-sky-50"
            >
              {btn.type === 'URL' && <LinkIcon className="size-3" />}
              {btn.type === 'PHONE_NUMBER' && <Phone className="size-3" />}
              {btn.text || `в•Әв–“в•Әв–’ ${i + 1}`}
            </button>
          ))}
        </div>
      )}
    </div>
  </div>
);

// ШёВӨВҖШёВӨВҖШёВӨВҖ Main Component ШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖШёВӨВҖ
export const WhatsAppTemplateBuilder: React.FC = () => {
  // ШёВӨВҖШёВӨВҖ Form state ШёВӨВҖШёВӨВҖ
  const [name, setName] = useState('');
  const [category, setCategory] = useState<'MARKETING' | 'UTILITY'>('MARKETING');
  const [language, setLanguage] = useState('ar');
  const [headerText, setHeaderText] = useState('');
  const [bodyText, setBodyText] = useState('');
  const [footerText, setFooterText] = useState('');
  const [buttons, setButtons] = useState<BtnDraft[]>([]);

  // ШёВӨВҖШёВӨВҖ List state ШёВӨВҖШёВӨВҖ
  const [templates, setTemplates] = useState<MetaTemplate[]>([]);
  const [loadingList, setLoadingList] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [deletingName, setDeletingName] = useState<string | null>(null);

  const fetchTemplates = useCallback(async () => {
    setLoadingList(true);
    try {
      const res = await fetch('/api/integrations/whatsapp/templates');
      const data = await res.json();
      setTemplates(data.templates || []);
    } catch {
      setTemplates([]);
    } finally {
      setLoadingList(false);
    }
  }, []);

  useEffect(() => {
    fetchTemplates();
  }, [fetchTemplates]);

  const addButton = () => {
    if (buttons.length >= 3) return;
    setButtons(prev => [...prev, { type: 'QUICK_REPLY', text: '' }]);
  };

  const updateButton = (i: number, patch: Partial<BtnDraft>) =>
    setButtons(prev => prev.map((b, idx) => (idx === i ? { ...b, ...patch } : b)));

  const removeButton = (i: number) =>
    setButtons(prev => prev.filter((_, idx) => idx !== i));

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccess('');
    if (!name || !bodyText) { setError('в•ӘШҜв•Әв”Ӯв”ҳГ  в•ӘШҜв”ҳВ„в”ҳГ©в•ӘШҜв”ҳВ„в•ӘШ° в”ҳГӘв”ҳВҶв•Әв•Ў в•ӘШҜв”ҳВ„в•Әв–’в•Әв”Ӯв•ӘШҜв”ҳВ„в•ӘШұ в”ҳГ в•Әв•–в”ҳВ„в”ҳГӘв•ӘШ°в•ӘШҜв”ҳВҶ'); return; }
    if (!/^[a-z0-9_]+$/.test(name)) { setError('в•ӘШҜв•Әв”Ӯв”ҳГ  в•ӘШҜв”ҳВ„в”ҳГ©в•ӘШҜв”ҳВ„в•ӘШ° в”ҳГЁв•ӘШҙв•ӘШ° в•ӘШ«в”ҳВҶ в”ҳГЁв”ҳГўв”ҳГӘв”ҳВҶ в•ӘШ°в•ӘШөв•Әв–’в”ҳГӘв”ҳВҒ в•ӘШӯв”ҳВҶв•ӘШҙв”ҳВ„в”ҳГЁв•Әв–“в”ҳГЁв•ӘШұ в•Әв•Ўв•Әв•‘в”ҳГЁв•Әв–’в•ӘШұ в”ҳГӘв•ӘШ«в•Әв–’в”ҳГ©в•ӘШҜв”ҳГ  в”ҳГӘв•Әв”Өв•Әв–’в•Әв•–в•ӘШұ в•Әв”Ӯв”ҳВҒв”ҳВ„в”ҳГЁв•ӘШұ в”ҳВҒв”ҳГ©в•Әв•–'); return; }

    setSubmitting(true);
    try {
      const res = await fetch('/api/integrations/whatsapp/templates', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ name, category, language, headerText: headerText || undefined, bodyText, footerText: footerText || undefined, buttons: buttons.length > 0 ? buttons : undefined }),
      });
      const data = await res.json();
      if (!res.ok) { setError(data.error || 'в”ҳВҒв•Әв”Өв”ҳВ„ в•ӘШӯв”ҳВҶв•Әв”Өв•ӘШҜв•ӘШ© в•ӘШҜв”ҳВ„в”ҳГ©в•ӘШҜв”ҳВ„в•ӘШ°'); return; }
      setSuccess(`в•ӘШІв”ҳГ  в•ӘШӯв•Әв–’в•Әв”Ӯв•ӘШҜв”ҳВ„ в•ӘШҜв”ҳВ„в”ҳГ©в•ӘШҜв”ҳВ„в•ӘШ° "${name}" в”ҳВ„в”ҳГ в”ҳГЁв•ӘШІв•ӘШҜ в”ҳВ„в”ҳВ„в”ҳГ в•Әв–’в•ӘШҜв•ӘШҙв•Әв•Јв•ӘШұ!`);
      setName(''); setHeaderText(''); setBodyText(''); setFooterText(''); setButtons([]);
      await fetchTemplates();
    } catch (err: any) {
      setError(err.message);
    } finally {
      setSubmitting(false);
    }
  };

  const handleDelete = async (templateName: string) => {
    if (!window.confirm(`в”ҳГ§в”ҳВ„ в•ӘШ«в”ҳВҶв•ӘШІ в”ҳГ в•ӘШІв•ӘШ«в”ҳГўв•ӘВ» в”ҳГ в”ҳВҶ в•ӘШөв•Әв–‘в”ҳВҒ в•ӘШҜв”ҳВ„в”ҳГ©в•ӘШҜв”ҳВ„в•ӘШ° "${templateName}"в•ӘШ§`)) return;
    setDeletingName(templateName);
    try {
      const res = await fetch(`/api/integrations/whatsapp/templates/${encodeURIComponent(templateName)}`, { method: 'DELETE' });
      if (res.ok) { await fetchTemplates(); }
    } finally {
      setDeletingName(null);
    }
  };

  return (
    <div className="space-y-10">
      {/* ШёВӨВҖШёВӨВҖ Header ШёВӨВҖШёВӨВҖ */}
      <div className="flex items-center gap-4">
        <div className="flex size-14 items-center justify-center rounded-2xl bg-emerald-100 text-emerald-600">
          <MessageSquare className="size-7" />
        </div>
        <div>
          <h1 className="text-2xl font-bold text-slate-900">в”ҳГ©в”ҳГӘв•ӘШҜв”ҳВ„в•ӘШ° в•ӘШҜв”ҳВ„в”ҳГӘв•ӘШҜв•ӘШІв•Әв”Ӯв•ӘШҜв•ӘШ°</h1>
          <p className="text-sm text-slate-500">в•ӘШ«в”ҳВҶв•Әв”Өв•ӘШ® в”ҳГ©в”ҳГӘв•ӘШҜв”ҳВ„в•ӘШ° в•Әв–’в•Әв”Ӯв•ӘШҜв•ӘШ®в”ҳВ„ в”ҳГӘв•ӘШ«в•Әв–’в•Әв”Ӯв”ҳВ„в”ҳГ§в•ӘШҜ в”ҳВ„в”ҳГ в”ҳГЁв•ӘШІв•ӘШҜ в”ҳВ„в”ҳВ„в”ҳГ в”ҳГӘв•ӘШҜв”ҳВҒв”ҳГ©в•ӘШұ в•Әв•Јв”ҳВ„в”ҳГЁв”ҳГ§в•ӘШҜ</p>
        </div>
      </div>

      {/* ШёВӨВҖШёВӨВҖ Builder + Preview ШёВӨВҖШёВӨВҖ */}
      <div className="grid gap-8 lg:grid-cols-2">
        {/* Form */}
        <form onSubmit={handleSubmit} className="space-y-5 rounded-2xl border border-slate-200 bg-white p-6 shadow-sm">
          <h2 className="text-lg font-semibold text-slate-800">в•ӘШӯв”ҳВҶв•Әв”Өв•ӘШҜв•ӘШ© в”ҳГ©в•ӘШҜв”ҳВ„в•ӘШ° в•ӘШҙв•ӘВ»в”ҳГЁв•ӘВ»</h2>

          {/* Name */}
          <div>
            <label className="mb-1 block text-sm font-medium text-slate-700">в•ӘШҜв•Әв”Ӯв”ҳГ  в•ӘШҜв”ҳВ„в”ҳГ©в•ӘШҜв”ҳВ„в•ӘШ°</label>
            <input
              type="text"
              value={name}
              onChange={e => setName(e.target.value.toLowerCase().replace(/[^a-z0-9_]/g, ''))}
              placeholder="в”ҳГ в•ӘШів•ӘШҜв”ҳВ„: welcome_message"
              className="w-full rounded-xl border border-slate-200 px-4 py-2.5 text-sm focus:border-emerald-400 focus:outline-none focus:ring-2 focus:ring-emerald-400/20"
            />
            <p className="mt-1 text-xs text-slate-400">в•ӘШөв•Әв–’в”ҳГӘв”ҳВҒ в•ӘШӯв”ҳВҶв•ӘШҙв”ҳВ„в”ҳГЁв•Әв–“в”ҳГЁв•ӘШұ в•Әв•Ўв•Әв•‘в”ҳГЁв•Әв–’в•ӘШұв•ӘГ® в•ӘШ«в•Әв–’в”ҳГ©в•ӘШҜв”ҳГ в•ӘГ® в”ҳГӘв•Әв”Өв•Әв–’в•Әв•–в•ӘШұ в•Әв”Ӯв”ҳВҒв”ҳВ„в”ҳГЁв•ӘШұ в”ҳВҒв”ҳГ©в•Әв•–</p>
          </div>

          {/* Category + Language */}
          <div className="grid grid-cols-2 gap-3">
            <div>
              <label className="mb-1 block text-sm font-medium text-slate-700">в•ӘШҜв”ҳВ„в”ҳВҒв•ӘШ®в•ӘШұ</label>
              <select
                value={category}
                onChange={e => setCategory(e.target.value as 'MARKETING' | 'UTILITY')}
                className="w-full rounded-xl border border-slate-200 px-3 py-2.5 text-sm focus:border-emerald-400 focus:outline-none"
              >
                <option value="MARKETING">в•ӘШІв•Әв”Ӯв”ҳГӘв”ҳГЁв”ҳГ©в”ҳГЁ (Marketing)</option>
                <option value="UTILITY">в•ӘВ«в•ӘВ»в”ҳГ в”ҳГЁ (Utility)</option>
              </select>
            </div>
            <div>
              <label className="mb-1 block text-sm font-medium text-slate-700">в•ӘШҜв”ҳВ„в”ҳВ„в•Әв•‘в•ӘШұ</label>
              <select
                value={language}
                onChange={e => setLanguage(e.target.value)}
                className="w-full rounded-xl border border-slate-200 px-3 py-2.5 text-sm focus:border-emerald-400 focus:outline-none"
              >
                <option value="ar">в•ӘШҜв”ҳВ„в•Әв•Јв•Әв–’в•ӘШ°в”ҳГЁв•ӘШұ (ar)</option>
                <option value="en_US">в•ӘШҜв”ҳВ„в•ӘШӯв”ҳВҶв•ӘШҙв”ҳВ„в”ҳГЁв•Әв–“в”ҳГЁв•ӘШұ (en_US)</option>
              </select>
            </div>
          </div>

